ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title ?name WHERE {
  ?a a :Movies .
  ?b a :Studio .
  ?a p:hasStudio ?b .
  ?a p:title ?title .
  ?b p:name ?name .
} }
  full: { SELECT ?title ?name ?full_name WHERE {
  ?a a :Movies .
  ?c a :Studio .
  ?a p:hasStudio ?c .
  ?p a :Producers .
  ?a p:hasProducer ?p .
  ?a p:title ?title .
  ?c p:name ?name .
  ?p p:name ?full_name .
} }
  component_2: { SELECT ?title ?full_name WHERE {
  ?a a :Movies .
  ?c a :Producers .
  ?a p:hasProducer ?c .
  ?a p:title ?title .
  ?c p:name ?full_name .
} }
}
